"crm.mb.section.label.sykw": "\u041d\u0435 \u043c\u043e\u0436\u0435\u0442\u0435 \u0434\u0430 \u0438\u043c\u0430\u0442\u0435 \u0435\u0442\u0438\u043a\u0435\u0442 \u043d\u0430 \u0440\u0430\u0437\u0434\u0435\u043b, \u043a\u043e\u0439\u0442\u043e \u0441\u044a\u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0430 \u043d\u0430 \u043a\u043b\u044e\u0447\u043e\u0432\u0430 \u0434\u0443\u043c\u0430 \u0432 \u0441\u0438\u0441\u0442\u0435\u043c\u0430\u0442\u0430. \u0412\u044a\u0432\u0435\u0434\u0435\u0442\u0435 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d \u0435\u0442\u0438\u043a\u0435\u0442.",
"crm.mb.field.label.sykw": "\u0422\u043e\u0437\u0438 \u0435\u0442\u0438\u043a\u0435\u0442 \u043d\u0430 \u043f\u043e\u043b\u0435 \u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u0430 \u043a\u043b\u044e\u0447\u043e\u0432\u0430 \u0434\u0443\u043c\u0430. \u0412\u044a\u0432\u0435\u0434\u0435\u0442\u0435 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d \u0435\u0442\u0438\u043a\u0435\u0442.",
