"crm.subform.primaryfield.identifier": "\u041f\u044a\u0440\u0432\u0438\u0447\u043d\u043e\u0442\u043e \u043f\u043e\u043b\u0435 \u0441\u043b\u0443\u0436\u0438 \u0437\u0430 \u0440\u0435\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u044f \u0437\u0430 \u0432\u0441\u044f\u043a\u0430 \u043a\u043e\u043b\u043e\u043d\u0430 \u0432 \u043f\u043e\u0434\u0444\u043e\u0440\u043c\u0430\u0442\u0430, \u0432\u0440\u0435\u043c\u0435\u0432\u0430\u0442\u0430 \u043b\u0438\u043d\u0438\u044f \u0438 \u0434\u0440\u0443\u0433\u0438 \u043c\u0435\u0441\u0442\u0430. \u041c\u0430\u0440\u043a\u0438\u0440\u0430\u043d\u0435 \u043d\u0430 \u043f\u043e\u043b\u0435 \u043a\u0430\u0442\u043e \u043f\u044a\u0440\u0432\u0438\u0447\u043d\u043e \u0432 \u0435\u0434\u043d\u043e \u043e\u0444\u043e\u0440\u043c\u043b\u0435\u043d\u0438\u0435 \u0441\u044a\u0449\u043e \u0433\u043e \u043c\u0430\u0440\u043a\u0438\u0440\u0430 \u043a\u0430\u0442\u043e \u043f\u044a\u0440\u0432\u0438\u0447\u043d\u043e \u0438 \u0432 \u0434\u0440\u0443\u0433\u0438 \u043e\u0444\u043e\u0440\u043c\u043b\u0435\u043d\u0438\u044f.",
"crm.mb.section.label.empt": "\u0415\u0442\u0438\u043a\u0435\u0442\u044a\u0442 \u0437\u0430 \u0440\u0430\u0437\u0434\u0435\u043b\u0430 \u043d\u0435 \u043c\u043e\u0436\u0435 \u0434\u0430 \u0435 \u043f\u0440\u0430\u0437\u0435\u043d.",
